import{RAWDriver as r,HWACDriver as e,TPHDDriver as o,ZTFHDriver as i,NLOCDriver as t,PKLADriver as s,UDKDriver as m}from"@triforce-heroes/triforce-commands";import{BMGDriver as D}from"./BMGDriver.js";import{KOEIDriver as v}from"./KOEIDriver.js";import{LBRSDriver as p}from"./LBRSDriver.js";import{LOSTDriver as a}from"./LOSTDriver.js";import{MSBTDriver as f}from"./MSBTDriver.js";import{NLOCDriver as n}from"./NLOCDriver.js";import{PKLADriver as c}from"./PKLADriver.js";import{UDKDriver as j}from"./UDKDriver.js";let u=Object.fromEntries(Object.entries({HWAC:e,RAW:r,TPHD:o,ZTFH:i,NLOC:t,PKLA:s,UDK:m}).map(([r,e])=>[r.toLowerCase(),e]));export const supportedSourceDrivers={bmg:D,koei:v,lbrs:p,msbt:f,nloc:n,pkla:c,lost:a,udk:j};export function loadSourceDriver(r){return supportedSourceDrivers[r.toLowerCase()]}export function loadEngineDriver(r){return u[r.toLowerCase()]}